import{_ as s,C as t,o as h,c as u,j as a,a as i,E as n,a3 as c}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第2章 得一","description":"帛书德篇第2章 · 得一（通行本第39章）","frontmatter":{"title":"帛书第2章 得一","description":"帛书德篇第2章 · 得一（通行本第39章）","category":"guide","aliases":["帛书第2章","马王堆老子2","通行本第39章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/dao-de-jing-boshu/chapter-02.md","filePath":"daoism/dao-de-jing-boshu/chapter-02.md","lastUpdated":1782666543000}'),m={name:"daoism/dao-de-jing-boshu/chapter-02.md"};function p(x,e,g,b,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),d=t("DaoLineGuide"),l=t("DaoKeywordCards");return h(),u("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第2章",tabindex:"-1"},[i("帛书老子第2章 "),a("a",{class:"header-anchor",href:"#帛书老子第2章","aria-label":'Permalink to "帛书老子第2章"'},"​")],-1)),n(o,{title:"第2章 得一",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第39章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第2章"},{label:"对照",text:"通行本第39章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(r,{paragraphs:["昔之得一者","天得一以清 地得一以宁,","神得一以霝 浴得一以盈","侯王得一以为天下正","亓致之也","谓天毋已清将恐裂","谓地毋已宁将恐发","谓神毋已霝将恐歇","谓浴毋已盈将恐竭","谓侯王毋已贵以高将恐蹶","故必贵而以贱为本","必高矣而以下为基","夫是以侯王自谓曰","孤 寡 不榖","此亓贱之为本与","非也","故致数与无与","是故不欲禄禄若玉","硌硌若石"]}),n(d,{lines:[{text:"昔之得一者",tone:"起",guide:"自古以来得到「一」（道的统一性）的——「一」是道的别名，万物得道则各正其命。"},{text:"天得一以清 地得一以宁",tone:"承",guide:"天得一道则清朗，地得一道则安宁——天地因得道而各正其位。"},{text:"神得一以霝 浴得一以盈",tone:"承",guide:"神得道则灵妙，山谷得道则充盈。帛书「霝」通「灵」，「浴」通「谷」——保留古字写法。"},{text:"侯王得一以为天下正",tone:"承",guide:"侯王得道则成为天下的准则与标准——「正」即准则，得道者自然为天下所归。"},{text:"亓致之也",tone:"转",guide:"推而言之——以下反过来论证失道的后果。帛书「亓」通「其」。"},{text:"谓天毋已清将恐裂",tone:"反",guide:"天若不再保持清朗，恐怕就要崩裂——得道则清，失道则裂。"},{text:"谓地毋已宁将恐发",tone:"反",guide:"地若不再保持安宁，恐怕就要爆发——得道则宁，失道则发。"},{text:"谓神毋已霝将恐歇",tone:"反",guide:"神若不再灵妙，恐怕就要停歇——得道则灵，失道则歇。"},{text:"谓浴毋已盈将恐竭",tone:"反",guide:"山谷若不再充盈，恐怕就要枯竭——得道则盈，失道则竭。"},{text:"谓侯王毋已贵以高将恐蹶",tone:"反",guide:"侯王若不再高贵，恐怕就要跌倒——「蹶」即颠覆、垮台，富贵离开了道的根基则危。"},{text:"故必贵而以贱为本",tone:"理",guide:"所以高贵必须以卑贱为根本——贵不离开贱，就像王不离开民，道不离开朴。"},{text:"必高矣而以下为基",tone:"理",guide:"高大必须以低下为基础——越高越要往下扎根，这是老子的「反向思维」。"},{text:"夫是以侯王自谓曰孤 寡 不榖 此亓贱之为本与 非也",tone:"问",guide:"所以侯王自称孤、寡、不榖（谷）——这不就是以贱为本吗？帛书「榖」通「谷」，不榖为君王自谦之称。"},{text:"故致数与无与",tone:"断",guide:"所以最高的荣誉就是没有荣誉——不需要被称赞，这才是真正的荣誉。"},{text:"是故不欲禄禄若玉 硌硌若石",tone:"收",guide:"所以不希望像美玉那样华丽珍贵（禄禄），宁愿像石头那样朴素坚实（硌硌）。华丽引祸，朴素久安。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(l,{items:[{term:"得一",pinyin:["dé","yī"],meaning:"得到「一」，一即道的统一性。天得一而清，地得一而宁——万物因得道而各正其位。本章围绕「得一」展开正反论证。",context:"昔之得一者——自古得道者皆如此。"},{term:"霝",pinyin:["líng"],meaning:"通「灵」——灵妙、神通。神得一以霝——神得道则灵妙。",context:"帛书用此古字，通行本作「灵」。"},{term:"浴",pinyin:["yù"],meaning:"通「谷」——山谷。浴得一以盈——山谷得道则充盈。",context:"帛书常以「浴」为「谷」。"},{term:"蹶",pinyin:["jué"],meaning:"跌倒、颠覆、垮台。侯王毋已贵以高将恐蹶——离开了谦下的根基，再高的地位也会崩塌。",context:"与「得一」形成对照：得道则安，失道则蹶。"},{term:"榖",pinyin:["gǔ"],meaning:"通「谷」，善、好的意思。不榖为古代君王自谦之称，意为「不善之人」。",context:"侯王自称孤、寡、不榖，正是以贱为本的体现。"},{term:"亓",pinyin:["qí"],meaning:"帛书古字，通「其」。全书通用。",context:"通行本全作「其」。"},{term:"禄禄",pinyin:["lù","lù"],meaning:"华丽珍贵的样子。不欲禄禄若玉——不希望像美玉那样华丽珍贵。",context:"与「硌硌若石」形成对比：宁可朴素坚实，不要华丽引祸。"},{term:"硌硌",pinyin:["luò","luò"],meaning:"石头坚硬朴实的样子。硌硌若石——像石头一样朴素坚实。",context:"老子主张「处其实不居其华」，本章以玉石之喻收束全篇。"}]}),e[3]||(e[3]=c('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「得一」，帛书此章围绕「天得一清」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第39章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const y=s(m,[["render",p]]);export{q as __pageData,y as default};
